@namespace sv_b4b9128137d541819c10157af790efff.Components.Pages.Apply

<div class="step-indicator">
    @for (int i = 0; i < StepNames.Count; i++)
    {
        var stepIndex = i;
        var css = stepIndex == CurrentStep ? "step active"
                : stepIndex < CurrentStep ? "step completed"
                : "step future";

        <div class="@css" @onclick="() => OnStepClick(stepIndex)">
            <span class="step-circle">
                @if (stepIndex < CurrentStep)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </span>
            <span class="step-label">@StepNames[stepIndex]</span>
        </div>

        @if (stepIndex < StepNames.Count - 1)
        {
            <div class="step-connector @(stepIndex < CurrentStep ? "completed" : "")"></div>
        }
    }
</div>

@code {
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnNavigate { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private async Task OnStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnNavigate.InvokeAsync(step);
        }
    }
}

@namespace sv_b4b9128137d541819c10157af790efff.Components.Pages.Apply

<div class="step-form personal-info-step">
    <h3>Personal Information</h3>

    <div class="form-group">
        <label for="fullName">Full Name *</label>
        <input id="fullName" type="text" @bind="Model.FullName" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="email">Email *</label>
        <input id="email" type="email" @bind="Model.Email" @bind:event="oninput" />
        @if (!string.IsNullOrEmpty(EmailError))
        {
            <span class="field-error">@EmailError</span>
        }
    </div>

    <div class="form-group">
        <label for="phone">Phone *</label>
        <input id="phone" type="tel" @bind="Model.Phone" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label for="address">Address *</label>
        <input id="address" type="text" @bind="Model.Address" @bind:event="oninput" />
    </div>

    @if (!string.IsNullOrEmpty(ValidationError))
    {
        <div class="validation-error">@ValidationError</div>
    }

    <div class="step-buttons">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
            @(IsValidating ? "Validating..." : "Next")
        </button>
    </div>
</div>

@code {
    [Parameter] public PersonalInfoModel Model { get; set; } = new();
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private string? ValidationError;
    private string? EmailError;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ValidationError = null;
        EmailError = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            ValidationError = "All fields are required.";
            return;
        }

        if (ValidateEmail is not null)
        {
            IsValidating = true;
            StateHasChanged();

            var isValid = await ValidateEmail(Model.Email);
            IsValidating = false;

            if (!isValid)
            {
                EmailError = "Please enter a valid email address.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }

    public class PersonalInfoModel
    {
        public string FullName { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
        public string Address { get; set; } = "";
    }
}

@namespace sv_b4b9128137d541819c10157af790efff.Components.Pages.Apply

<div class="work-entry-form">
    <div class="entry-header">
        <h4>Position @(Index + 1)</h4>
        @if (CanRemove)
        {
            <button class="btn btn-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
        }
    </div>

    <div class="form-group">
        <label>Company Name *</label>
        <input type="text" @bind="Model.Company" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label>Job Title *</label>
