@namespace sv_b4b9128137d541819c10157af790efff.Components.Pages.Apply

<div class="step-form review-step">
    <h3>Review & Submit</h3>

    @if (IsSubmitted)
    {
        <div class="submission-confirmation">
            <h4>&#10003; Application Submitted Successfully!</h4>
            <p>Your application ID is: <strong>@ApplicationId</strong></p>
            <p>Thank you for applying. We will review your application and get back to you.</p>
        </div>
    }
    else
    {
        <div class="review-section">
            <div class="review-header">
                <h4>Personal Information</h4>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(0)">Edit</button>
            </div>
            <dl>
                <dt>Full Name</dt><dd>@Personal.FullName</dd>
                <dt>Email</dt><dd>@Personal.Email</dd>
                <dt>Phone</dt><dd>@Personal.Phone</dd>
                <dt>Address</dt><dd>@Personal.Address</dd>
            </dl>
        </div>

        <div class="review-section">
            <div class="review-header">
                <h4>Work History</h4>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-entry">
                    <strong>@entry.Title</strong> at @entry.Company
                    <br />
                    <span class="date-range">
                        @entry.StartDate.ToString("MMM yyyy") &mdash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p>@entry.Description</p>
                    }
                </div>
            }
        </div>

        <div class="review-section">
            <div class="review-header">
                <h4>References</h4>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
            </div>
            @foreach (var reference in References)
            {
                <div class="review-entry">
                    <strong>@reference.Name</strong> (@reference.Relationship)
                    <br />@reference.Email | @reference.Phone
                </div>
            }
        </div>

        <div class="review-section">
            <div class="review-header">
                <h4>Cover Letter</h4>
                <button class="btn-link" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
            </div>
            <p class="cover-letter-preview">@CoverLetter</p>
        </div>

        @if (!string.IsNullOrEmpty(SubmitError))
        {
            <div class="validation-error">@SubmitError</div>
        }

        <div class="step-buttons">
            <button class="btn btn-outline" @onclick="OnBack">Back</button>
            <button class="btn btn-primary btn-submit" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @(IsSubmitting ? "Submitting..." : "Submit Application")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public PersonalInfoStep.PersonalInfoModel Personal { get; set; } = new();
    [Parameter] public List<WorkEntryForm.WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public List<ReferenceForm.ReferenceModel> References { get; set; } = new();
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public Func<Task<int>>? OnSubmit { get; set; }

    private bool IsSubmitting;
    private bool IsSubmitted;
    private int? ApplicationId;
    private string? SubmitError;

    private async Task HandleSubmit()
    {
        if (OnSubmit is null) return;

        IsSubmitting = true;
        SubmitError = null;
        StateHasChanged();

        try
        {
            ApplicationId = await OnSubmit();
            IsSubmitted = true;
        }
        catch (Exception ex)
        {
            SubmitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

@namespace sv_b4b9128137d541819c10157af790efff.Components.Pages.Apply

<div class="step-indicator">
    @for (int i = 0; i < StepNames.Count; i++)
    {
        var stepIndex = i;
        var css = stepIndex == CurrentStep ? "step active"
                : stepIndex < CurrentStep ? "step completed"
                : "step future";

        <div class="@css" @onclick="() => OnStepClick(stepIndex)">
            <span class="step-circle">
                @if (stepIndex < CurrentStep)
                {
                    <span>&#10003;</span>
                }
                else
                {
                    <span>@(stepIndex + 1)</span>
                }
            </span>
            <span class="step-label">@StepNames[stepIndex]</span>
        </div>

        @if (stepIndex < StepNames.Count - 1)
        {
            <div class="step-connector @(stepIndex < CurrentStep ? "completed" : "")"></div>
        }
    }
</div>

@code {
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnNavigate { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private async Task OnStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnNavigate.InvokeAsync(step);
        }
    }
}

