<div class="step-form personal-info-step">
    <h3>Personal Information</h3>

    <div class="form-group">
        <label for="fullName">Full Name *</label>
        <input id="fullName" type="text" @bind="Model.FullName" @bind:event="oninput" />
    </div>

    <div class="form-group">
