+
+<div class="step-indicator">
+    @for (int i = 0; i < StepNames.Count; i++)
+    {
+        var stepIndex = i;
+        var css = stepIndex == CurrentStep ? "step active"
+                : stepIndex < CurrentStep ? "step completed"
+                : "step future";
+
+        <div class="@css" @onclick="() => OnStepClick(stepIndex)">
+            <span class="step-circle">
+                @if (stepIndex < CurrentStep)
+                {
+                    <span>&#10003;</span>
+                }
+                else
+                {
+                    <span>@(stepIndex + 1)</span>
+                }
+            </span>
+            <span class="step-label">@StepNames[stepIndex]</span>
+        </div>
+
+        @if (stepIndex < StepNames.Count - 1)
+        {
+            <div class="step-connector @(stepIndex < CurrentStep ? "completed" : "")"></div>
+        }
+    }
+</div>
+
+@code {
+    [Parameter] public int CurrentStep { get; set; }
+    [Parameter] public EventCallback<int> OnNavigate { get; set; }
+
+    private static readonly List<string> StepNames = new()
+    {
+        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
+    };
+
+    private async Task OnStepClick(int step)
+    {
+        if (step < CurrentStep)
+        {
+            await OnNavigate.InvokeAsync(step);
+        }
+    }
+}
+

