@namespace sv_b4b9128137d541819c10157af790efff.Components.Pages.Apply

<div class="work-entry-form">
    <div class="entry-header">
        <h4>Position @(Index + 1)</h4>
        @if (CanRemove)
        {
            <button class="btn btn-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
        }
    </div>

    <div class="form-group">
        <label>Company Name *</label>
        <input type="text" @bind="Model.Company" @bind:event="oninput" />
    </div>

    <div class="form-group">
        <label>Job Title *</label>
        <input type="text" @bind="Model.Title" @bind:event="oninput" />
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Start Date *</label>
            <input type="date" @bind="Model.StartDate" />
        </div>
        <div class="form-group">
            <label>End Date</label>
            <input type="date" @bind="Model.EndDate" disabled="@Model.IsCurrent" />
            <label class="checkbox-label">
                <input type="checkbox" @bind="Model.IsCurrent" /> Currently working here
            </label>
        </div>
    </div>

    <div class="form-group">
        <label>Description</label>
        <textarea rows="3" @bind="Model.Description" @bind:event="oninput"></textarea>
    </div>
</div>

@code {
    [Parameter] public WorkEntryModel Model { get; set; } = new();
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; } = DateTime.Today;
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }
}

@namespace sv_b4b9128137d541819c10157af790efff.Components.Pages.Apply

<div class="step-form work-history-step">
    <h3>Work History</h3>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Model="Entries[index]" Index="index"
                       CanRemove="Entries.Count > 1"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button class="btn btn-secondary" @onclick="AddEntry">+ Add Another Position</button>

    @if (!string.IsNullOrEmpty(ValidationError))
    {
        <div class="validation-error">@ValidationError</div>
    }

    <div class="step-buttons">
        <button class="btn btn-outline" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public List<WorkEntryForm.WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ValidationError;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryForm.WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        ValidationError = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ValidationError = "Company name and job title are required for each position.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

