@namespace sv_b4b9128137d541819c10157af790efff.Components.Pages.Apply

<div class="step-form references-step">
    <h3>References</h3>
    <p class="step-description">Please provide 2-3 professional references.</p>

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Model="References[index]" Index="index"
                       CanRemove="References.Count > 2"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button class="btn btn-secondary" @onclick="AddReference">+ Add Reference</button>
    }

    @if (!string.IsNullOrEmpty(ValidationError))
    {
        <div class="validation-error">@ValidationError</div>
    }

    <div class="step-buttons">
        <button class="btn btn-outline" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public List<ReferenceForm.ReferenceModel> References { get; set; } = new();
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ValidationError;

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceForm.ReferenceModel());
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        ValidationError = null;

        foreach (var reference in References)
        {
            if (string.IsNullOrWhiteSpace(reference.Name) ||
                string.IsNullOrWhiteSpace(reference.Relationship) ||
                string.IsNullOrWhiteSpace(reference.Email) ||
                string.IsNullOrWhiteSpace(reference.Phone))
            {
                ValidationError = "All fields are required for each reference.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

