@namespace sv_b4b9128137d541819c10157af790efff.Components.Pages.Apply

<div class="step-form cover-letter-step">
    <h3>Cover Letter</h3>

    <div class="form-group">
        <label for="coverLetter">Write your cover letter</label>
        <textarea id="coverLetter" rows="12" maxlength="@MaxLength"
                  @bind="CoverLetterText" @bind:event="oninput"></textarea>
        <div class="char-count @(CoverLetterText.Length > MaxLength ? "over-limit" : "")">
            @CoverLetterText.Length / @MaxLength characters
        </div>
    </div>

    @if (!string.IsNullOrEmpty(ValidationError))
    {
        <div class="validation-error">@ValidationError</div>
    }

    <div class="step-buttons">
        <button class="btn btn-outline" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public string CoverLetterText { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterTextChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private const int MaxLength = 2000;
    private string? ValidationError;

    private async Task HandleNext()
    {
        ValidationError = null;

        if (string.IsNullOrWhiteSpace(CoverLetterText))
        {
            ValidationError = "Please write a cover letter.";
            return;
        }

        await CoverLetterTextChanged.InvokeAsync(CoverLetterText);
        await OnNext.InvokeAsync();
    }
}

