@page "/apply"
@rendermode InteractiveServer
@using sv_b4b9128137d541819c10157af790efff.Models
@using sv_b4b9128137d541819c10157af790efff.Components.Pages.Apply

@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-page">
    <h2>Job Application</h2>

    <StepIndicator CurrentStep="currentStep" OnNavigate="NavigateToStep" />

    <div class="step-content">
        @switch (currentStep)
        {
            case 0:
                <PersonalInfoStep Model="personalInfo"
                                  ValidateEmail="ApplicationService.ValidateEmailAsync"
                                  OnNext="NextStep" />
                break;
            case 1:
                <WorkHistoryStep Entries="workEntries"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 2:
                <ReferencesStep References="references"
                                OnNext="NextStep"
                                OnBack="PreviousStep" />
                break;
            case 3:
                <CoverLetterStep @bind-CoverLetterText="coverLetter"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 4:
                <ReviewStep Personal="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="coverLetter"
                            OnEdit="NavigateToStep"
                            OnBack="PreviousStep"
                            OnSubmit="SubmitApplication" />
                break;
        }
    </div>
</div>

@code {
    private int currentStep = 0;

    private PersonalInfoStep.PersonalInfoModel personalInfo = new();
    private List<WorkEntryForm.WorkEntryModel> workEntries = new() { new() };
    private List<ReferenceForm.ReferenceModel> references = new() { new(), new() };
    private string coverLetter = "";

    private void NextStep() => currentStep++;
    private void PreviousStep() => currentStep--;
