    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 2rem;
    flex-wrap: wrap;
    gap: 0.25rem;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    cursor: default;
    opacity: 0.4;
    transition: opacity 0.2s;
}

.step.active {
    opacity: 1;
}

.step.completed {
    opacity: 1;
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    background: #e0e0e0;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.9rem;
    margin-bottom: 0.25rem;
}

.step.active .step-circle {
    background: #1976d2;
    color: white;
}

.step.completed .step-circle {
    background: #4caf50;
    color: white;
}

.step-label {
    font-size: 0.75rem;
    text-align: center;
    max-width: 80px;
}

.step-connector {
    width: 40px;
    height: 2px;
    background: #e0e0e0;
    margin: 0 0.25rem;
    align-self: center;
    margin-bottom: 1.25rem;
}

.step-connector.completed {
    background: #4caf50;
}

/* Form Styles */
.step-form {
    background: #fafafa;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 2rem;
